import{_ as e,c as t,o as r,a3 as o}from"./chunks/framework.D_vaOmZD.js";const u=JSON.parse('{"title":"Permissions","titleTemplate":"Simple Voice Chat","description":"","frontmatter":{"titleTemplate":"Simple Voice Chat","aside":false},"headers":[],"relativePath":"minecraft/voicechat/wiki/permissions.md","filePath":"minecraft/voicechat/wiki/permissions.md"}'),s={name:"minecraft/voicechat/wiki/permissions.md"},i=o('<h1 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h1><p>Simple Voice Chat has permissions for the <a href="https://bukkit.fandom.com/wiki/Understanding_Permissions" target="_blank" rel="noreferrer">Bukkit permission system</a>, the <a href="https://mcforge.readthedocs.io/en/1.12.x/utilities/permissionapi/" target="_blank" rel="noreferrer">Forge permission API</a> and the <a href="https://github.com/lucko/fabric-permissions-api" target="_blank" rel="noreferrer">Fabric Permissions API</a>.</p><div class="danger custom-block"><p class="custom-block-title">NOTE</p><p>We don&#39;t support hybrid servers! Please either use only plugins or only mods on your server.</p><p>If you for some reason don&#39;t have permission for something that is granted to everyone by default, you might have misconfigured your permissions manager or are using a hybrid server.</p></div><table tabindex="0"><thead><tr><th>Permission Node</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>voicechat.listen</code></td><td>Granted for everyone</td><td>If players should be able to hear audio from the voice chat.</td></tr><tr><td><code>voicechat.speak</code></td><td>Granted for everyone</td><td>If players should be able to transmit audio.</td></tr><tr><td><code>voicechat.groups</code></td><td>Granted for everyone</td><td>If players should be able to join groups.</td></tr><tr><td><code>voicechat.admin</code></td><td>Only granted for server operators</td><td>For administrative purposes like the <code>/voicechat test</code> command.</td></tr></tbody></table>',4),a=[i];function d(n,c,h,m,p,l){return r(),t("div",null,a)}const _=e(s,[["render",d]]);export{u as __pageData,_ as default};
